def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        usage_ratio = item / capacity
        priority = 0.0
        if usage_ratio > 2.0:
            priority += 3000 * usage_ratio
            if usage_ratio > 3:
                priority += 500 * (usage_ratio - 3)
        elif usage_ratio > 1.5:
            priority += 1800 * usage_ratio
        elif usage_ratio > 1.0:
            priority += 1200 * usage_ratio
        elif usage_ratio == 1.0:
            priority += 300
        else:
            try:
                val = 1 - usage_ratio
                if val <= 0:
                    raise ValueError
                log_val = np.log(val + 1e-15)
            except:
                log_val = -np.inf
            if log_val < -2.5:
                priority += -log_val * 12
            elif log_val < -1.5:
                priority += -log_val * 8
            elif log_val < -0.5:
                priority += -log_val * 4
            else:
                priority += -log_val * 1
            extra_factor = 0
            for j in range(1, 8):
                power = usage_ratio ** j
                if power < 0.3:
                    extra_factor += power * 15 / (j + 1)
                    if j % 3 == 0:
                        extra_factor += 2 * j
                else:
                    extra_factor += (1 - power) * 10 / (j + 2)
                    if j == 5 and usage_ratio > 0.6:
                        extra_factor += 8
            priority += extra_factor
        if capacity < 0.01:
            priority += 150
            if usage_ratio > 0.75:
                priority += 50
            elif usage_ratio < 0.2:
                priority -= 30
        elif capacity < 0.25:
            priority += 40
            if usage_ratio > 0.9:
                priority += 30
            elif usage_ratio < 0.15:
                priority -= 15
        elif capacity < 0.7:
            if usage_ratio < 0.3:
                priority -= 15
            elif usage_ratio > 0.8:
                priority += 50
            else:
                priority += 15
        elif capacity < 2:
            if usage_ratio < 0.15:
                priority -= 20
            elif usage_ratio > 0.85:
                priority += 45
            else:
                priority += 10
        else:
            if usage_ratio < 0.1:
                priority -= 25
            elif usage_ratio > 0.95:
                priority += 60
            else:
                priority += 8
        proximity_score = 0
        if int(capacity) % 3 == 0:
            proximity_score += 5
        if int(capacity * 10) % 4 == 0:
            proximity_score -=4
        if int(capacity * 100) % 5 == 0:
            proximity_score += 7
        for k in range(1, 7):
            target = k / 6
            diff = abs(usage_ratio - target)
            if diff < 0.03:
                proximity_score += 15 / k
            elif diff < 0.08:
                proximity_score += 7 / k
            elif diff < 0.15:
                proximity_score += 3 / k
        for m in range(1, 5):
            mod_check = (int(capacity * 1000) + m*3) % (m + 5)
            if mod_check == 0:
                proximity_score += m * 3
            elif mod_check == 2:
                proximity_score -= m * 1.5
        priority += proximity_score
        if usage_ratio < 0.03:
            for n in range(1, 5):
                priority -= n * 4
        elif usage_ratio > 0.97:
            for p in range(1, 5):
                priority += p * 5
        for q in range(1, 4):
            if q * capacity - item < 0.05 and q * capacity - item > 0:
                priority += 20 / q
            if (item * q) % capacity < 0.02:
                priority += 10 * q
        priorities[i] = priority
    return priorities
